import React from 'react';
import { navigate } from 'gatsby';
import { GatsbyImage } from 'gatsby-plugin-image';
import Box from '@mui/material/Box';
import Grid from '@mui/material/Grid';
import Link from '@mui/material/Link';

const Thumbnails = ({ datas, category }) => {
  return (
    <Grid container direction='row' justifyContent='center' spacing={4}>
      {datas
        .filter(data => {
          const _category = data.category;

          // category:all
          if (!category) {
            return true;
          }

          return _category === category;
        })
        .map(({ name, link, image }, i) => (
          <Grid
            item
            key={i}
            sx={{
              transition: 'all 250ms ease-out'
            }}
          >
            <Link
              href={`/works/${link}/`}
              onClick={e => {
                e.preventDefault();
                navigate(`/works/${link}/`);
              }}
            >
              <Box
                sx={{
                  width: {
                    md: 200,
                    sm: 200,
                    xs: 150
                  },
                  height: {
                    md: 200,
                    sm: 200,
                    xs: 150
                  },
                  overflow: 'hidden',
                  transition: 'all 250ms ease-out'
                }}
              >
                <GatsbyImage
                  image={image}
                  alt={name}
                  layout='fullWidth'
                  placeholder='blurred'
                  style={{
                    width: '100%',
                    height: '100%',
                    pointerEvents: 'none',
                    userSelect: 'none'
                  }}
                />
              </Box>
            </Link>
          </Grid>
        ))}
    </Grid>
  );
};

export default Thumbnails;
